import React, { useState, useMemo } from 'react';

const theme = {
  bg: '#0f172a',
  surface: '#1e293b',
  card: '#334155',
  text: '#f8fafc',
  muted: '#94a3b8',
  dim: '#64748b',
  highlight: '#fbbf24',
  selected: '#3b82f6',
  match: '#22c55e',
  filtered: '#a78bfa',
};

const presets = [
  {
    name: 'Colors & Animals',
    data: [
      ['red', 'cat'], ['blue', 'dog'], ['red', 'dog'], ['red', 'cat'],
      ['blue', 'cat'], ['red', 'dog']
    ],
    xLabel: 'Color',
    yLabel: 'Animal',
  },
  {
    name: 'Weather & Activity',
    data: [
      ['sunny', 'walk'], ['rainy', 'read'], ['sunny', 'run'],
      ['cloudy', 'read'], ['sunny', 'walk'], ['rainy', 'sleep'],
      ['sunny', 'swim'], ['cloudy', 'walk']
    ],
    xLabel: 'Weather',
    yLabel: 'Activity',
  },
  {
    name: 'Gender & Response',
    data: [
      ['male', 'yes'], ['female', 'no'], ['male', 'no'],
      ['male', 'yes'], ['female', 'yes'], ['male', 'yes'],
      ['female', 'no'], ['female', 'yes']
    ],
    xLabel: 'Gender',
    yLabel: 'Response',
  },
];

export default function App() {
  const [presetIdx, setPresetIdx] = useState(0);
  const [selectedX, setSelectedX] = useState(null);
  const [selectedY, setSelectedY] = useState(null);

  const preset = presets[presetIdx];
  const { data, xLabel, yLabel } = preset;

  // Get unique values
  const xValues = useMemo(() => [...new Set(data.map(d => d[0]))], [presetIdx]);
  const yValues = useMemo(() => [...new Set(data.map(d => d[1]))], [presetIdx]);

  // Calculate counts and probability
  const calculation = useMemo(() => {
    if (!selectedX) return null;

    const filteredByX = data.filter(d => d[0] === selectedX);
    const countX = filteredByX.length;

    if (countX === 0) return { countX: 0, countXY: 0, probability: 0 };

    const countXY = selectedY ? filteredByX.filter(d => d[1] === selectedY).length : 0;
    const probability = selectedY ? countXY / countX : 0;

    return { countX, countXY, probability };
  }, [data, selectedX, selectedY]);

  // Reset selections when changing preset
  const handlePresetChange = (idx) => {
    setPresetIdx(idx);
    setSelectedX(null);
    setSelectedY(null);
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Conditional Probability</h1>

      <div style={styles.conceptBox}>
        <div style={styles.conceptTitle}>P(Y=y | X=x) = "Given X is x, what's the chance Y is y?"</div>
        <p style={styles.conceptText}>
          Filter the data to only rows where X=x, then count how many have Y=y. 
          Divide by total filtered rows.
        </p>
      </div>

      <div style={styles.presetRow}>
        {presets.map((p, i) => (
          <button key={i} onClick={() => handlePresetChange(i)}
            style={{...styles.presetBtn, background: presetIdx === i ? theme.highlight : theme.card,
              color: presetIdx === i ? theme.bg : theme.text}}>
            {p.name}
          </button>
        ))}
      </div>

      <div style={styles.mainArea}>
        {/* Data visualization */}
        <div style={styles.dataSection}>
          <div style={styles.sectionTitle}>Dataset ({data.length} observations)</div>
          <div style={styles.dataGrid}>
            {data.map((row, i) => {
              const matchesX = selectedX && row[0] === selectedX;
              const matchesY = selectedY && row[1] === selectedY;
              const isMatch = matchesX && matchesY;
              const isFiltered = matchesX && !matchesY && selectedY;

              return (
                <div key={i} style={{
                  ...styles.dataCard,
                  background: isMatch ? theme.match : (matchesX ? theme.filtered : theme.surface),
                  opacity: selectedX && !matchesX ? 0.3 : 1,
                  borderColor: isMatch ? theme.match : (matchesX ? theme.filtered : theme.card),
                }}>
                  <div style={{...styles.dataX, color: matchesX ? theme.bg : theme.selected}}>{row[0]}</div>
                  <div style={{...styles.dataY, color: isMatch ? theme.bg : (matchesX ? theme.bg : theme.match)}}>{row[1]}</div>
                </div>
              );
            })}
          </div>

          <div style={styles.legendRow}>
            <div style={styles.legendItem}>
              <div style={{...styles.legendBox, background: theme.surface}} />
              <span>All data</span>
            </div>
            <div style={styles.legendItem}>
              <div style={{...styles.legendBox, background: theme.filtered}} />
              <span>X matches</span>
            </div>
            <div style={styles.legendItem}>
              <div style={{...styles.legendBox, background: theme.match}} />
              <span>X and Y match</span>
            </div>
          </div>
        </div>

        {/* Controls and calculation */}
        <div style={styles.controlsSection}>
          <div style={styles.selectorBox}>
            <div style={styles.selectorTitle}>1. Select X value (condition on)</div>
            <div style={styles.selectorLabel}>{xLabel}:</div>
            <div style={styles.optionsRow}>
              {xValues.map(x => (
                <button key={x} onClick={() => setSelectedX(x)}
                  style={{...styles.optionBtn, 
                    background: selectedX === x ? theme.selected : theme.card,
                    borderColor: selectedX === x ? theme.selected : theme.card}}>
                  {x}
                </button>
              ))}
            </div>
          </div>

          <div style={{...styles.selectorBox, opacity: selectedX ? 1 : 0.4}}>
            <div style={styles.selectorTitle}>2. Select Y value (what we want)</div>
            <div style={styles.selectorLabel}>{yLabel}:</div>
            <div style={styles.optionsRow}>
              {yValues.map(y => (
                <button key={y} onClick={() => selectedX && setSelectedY(y)}
                  style={{...styles.optionBtn, 
                    background: selectedY === y ? theme.match : theme.card,
                    borderColor: selectedY === y ? theme.match : theme.card,
                    cursor: selectedX ? 'pointer' : 'not-allowed'}}>
                  {y}
                </button>
              ))}
            </div>
          </div>

          {/* Calculation display */}
          <div style={styles.calcBox}>
            <div style={styles.calcTitle}>Calculation</div>

            {!selectedX ? (
              <div style={styles.calcPrompt}>Select an X value to start</div>
            ) : !selectedY ? (
              <div style={styles.calcStep}>
                <div style={styles.calcLine}>
                  Filtered to <span style={{color: theme.selected}}>{xLabel}={selectedX}</span>: 
                  <span style={{color: theme.filtered, fontWeight: 700}}> {calculation?.countX} rows</span>
                </div>
                <div style={styles.calcPrompt}>Now select a Y value</div>
              </div>
            ) : (
              <div style={styles.calcStep}>
                <div style={styles.calcLine}>
                  Count of <span style={{color: theme.selected}}>{xLabel}={selectedX}</span>: 
                  <span style={{fontWeight: 700}}> {calculation?.countX}</span>
                </div>
                <div style={styles.calcLine}>
                  Count of <span style={{color: theme.selected}}>{xLabel}={selectedX}</span> AND 
                  <span style={{color: theme.match}}> {yLabel}={selectedY}</span>: 
                  <span style={{fontWeight: 700}}> {calculation?.countXY}</span>
                </div>
                <div style={styles.formula}>
                  P({yLabel}={selectedY} | {xLabel}={selectedX}) = {calculation?.countXY} / {calculation?.countX}
                </div>
              </div>
            )}

            {selectedX && selectedY && (
              <div style={styles.resultBox}>
                <div style={styles.resultLabel}>Result</div>
                <div style={{...styles.resultValue, color: theme.highlight}}>
                  {calculation?.probability.toFixed(4)}
                </div>
                <div style={styles.resultPercent}>
                  ({(calculation?.probability * 100).toFixed(1)}%)
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      <div style={styles.insight}>
        <strong>The formula:</strong> P(Y=y|X=x) = Count(X=x AND Y=y) / Count(X=x). 
        If X=x never occurs, we return 0. This is the foundation of Bayesian reasoning and classifiers like Naive Bayes.
      </div>
    </div>
  );
}

const styles = {
  container: { fontFamily: "'Inter', system-ui, sans-serif", background: theme.bg, color: theme.text, padding: 16, maxWidth: 750, margin: '0 auto' },
  title: { fontSize: 20, fontWeight: 700, margin: '0 0 12px', textAlign: 'center' },
  conceptBox: { background: theme.surface, borderRadius: 10, padding: 14, marginBottom: 14, borderLeft: `4px solid ${theme.highlight}` },
  conceptTitle: { fontSize: 13, fontWeight: 700, color: theme.highlight, marginBottom: 6 },
  conceptText: { fontSize: 12, color: theme.muted, margin: 0, lineHeight: 1.6 },
  presetRow: { display: 'flex', gap: 8, marginBottom: 14, justifyContent: 'center', flexWrap: 'wrap' },
  presetBtn: { padding: '8px 14px', border: 'none', borderRadius: 6, fontSize: 11, fontWeight: 600, cursor: 'pointer' },
  mainArea: { display: 'flex', gap: 14, marginBottom: 14 },
