  dataCard: { padding: '8px 12px', borderRadius: 6, borderWidth: 2, borderStyle: 'solid', transition: 'all 0.2s', minWidth: 70, textAlign: 'center' },
  dataX: { fontSize: 11, fontWeight: 600 },
  dataY: { fontSize: 10, marginTop: 2 },
  legendRow: { display: 'flex', gap: 12, marginTop: 12, flexWrap: 'wrap' },
  legendItem: { display: 'flex', alignItems: 'center', gap: 5, fontSize: 10, color: theme.dim },
  legendBox: { width: 14, height: 14, borderRadius: 3 },
  controlsSection: { width: 280, display: 'flex', flexDirection: 'column', gap: 10, flexShrink: 0 },
  selectorBox: { background: theme.surface, borderRadius: 8, padding: 12, transition: 'opacity 0.2s' },
  selectorTitle: { fontSize: 11, fontWeight: 600, marginBottom: 8, color: theme.muted },
  selectorLabel: { fontSize: 10, color: theme.dim, marginBottom: 6 },
  optionsRow: { display: 'flex', flexWrap: 'wrap', gap: 6 },
  optionBtn: { padding: '6px 12px', border: '2px solid', borderRadius: 5, fontSize: 11, fontWeight: 600, cursor: 'pointer', color: theme.text, transition: 'all 0.15s' },
  calcBox: { background: theme.surface, borderRadius: 8, padding: 12, flex: 1 },
  calcTitle: { fontSize: 12, fontWeight: 700, marginBottom: 10, color: theme.muted },
  calcPrompt: { fontSize: 11, color: theme.dim, fontStyle: 'italic' },
  calcStep: {},
  calcLine: { fontSize: 11, marginBottom: 6, lineHeight: 1.5 },
  formula: { fontSize: 12, fontFamily: 'monospace', background: theme.bg, padding: 10, borderRadius: 6, marginTop: 8 },
  resultBox: { background: theme.bg, borderRadius: 8, padding: 12, marginTop: 10, textAlign: 'center' },
  resultLabel: { fontSize: 10, color: theme.dim, marginBottom: 4 },
  resultValue: { fontSize: 28, fontWeight: 700, fontFamily: 'monospace' },
  resultPercent: { fontSize: 12, color: theme.muted, marginTop: 2 },
  insight: { background: `${theme.selected}15`, borderRadius: 8, padding: 12, fontSize: 11, lineHeight: 1.6, color: theme.muted, borderLeft: `3px solid ${theme.selected}` },
};
